const { app } = require('@azure/functions');
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

// SECURE IMPLEMENTATION
// API keys and secrets are retrieved from environment variables.
// In Azure Functions, these should be configured as Application Settings,
// which are encrypted at rest. For production, use Key Vault references
// in Application Settings (e.g., @Microsoft.KeyVault(SecretUri=https://...)).
//
// Required Application Settings:
//   SENDGRID_API_KEY - Your SendGrid API key
//   TWILIO_ACCOUNT_SID - Your Twilio Account SID
//   TWILIO_AUTH_TOKEN - Your Twilio Auth Token
//   TWILIO_PHONE_NUMBER - Your Twilio phone number
//   NOTIFICATION_FROM_EMAIL - Sender email address

function getSendGridClient() {
    const apiKey = process.env.SENDGRID_API_KEY;
    if (!apiKey) {
        throw new Error('SENDGRID_API_KEY environment variable is not configured. Set it in Azure Function Application Settings.');
    }
    sgMail.setApiKey(apiKey);
    return sgMail;
}

function getTwilioClient() {
    const accountSid = process.env.TWILIO_ACCOUNT_SID;
    const authToken = process.env.TWILIO_AUTH_TOKEN;
    if (!accountSid || !authToken) {
        throw new Error('TWILIO_ACCOUNT_SID and TWILIO_AUTH_TOKEN environment variables must be configured. Set them in Azure Function Application Settings.');
    }
    return twilio(accountSid, authToken);
}

app.http('sendEmail', {
    methods: ['POST'],
    authLevel: 'function',
    route: 'notifications/email',
    handler: async (request, context) => {
        context.log('Processing email notification request');

        try {
            const body = await request.json();

            // Input validation
            if (!body.to || !body.subject || !body.body) {
                return {
                    status: 400,
                    jsonBody: {
                        success: false,
                        error: 'Missing required fields: to, subject, body'
                    }
                };
            }

            // Validate email format
            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            if (!emailRegex.test(body.to)) {
                return {
                    status: 400,
                    jsonBody: {
                        success: false,
                        error: 'Invalid email address format'
                    }
                };
            }

            const fromEmail = process.env.NOTIFICATION_FROM_EMAIL;
            if (!fromEmail) {
                throw new Error('NOTIFICATION_FROM_EMAIL environment variable is not configured.');
            }

            const client = getSendGridClient();

            const msg = {
                to: body.to,
                from: fromEmail,
                subject: body.subject,
                text: body.body,
                html: body.htmlBody || undefined
            };

            await client.send(msg);

            context.log(`Email sent successfully to ${body.to}`);

            return {
                status: 200,
                jsonBody: {
                    success: true,
                    message: 'Email sent successfully'
                }
            };
        } catch (error) {
            context.error('Error sending email:', error.message);
            // Do not leak internal error details to the client
            return {
                status: 500,
                jsonBody: {
                    success: false,
                    error: 'Failed to send email. Please try again later.'
                }
            };
        }
    }
});

app.http('sendSms', {
    methods: ['POST'],
    authLevel: 'function',
    route: 'notifications/sms',
    handler: async (request, context) => {
        context.log('Processing SMS notification request');

        try {
            const body = await request.json();

            // Input validation
            if (!body.to || !body.message) {
                return {
                    status: 400,
                    jsonBody: {
                        success: false,
                        error: 'Missing required fields: to, message'
                    }
                };
            }

            // Validate phone number format (E.164)
            const phoneRegex = /^\+[1-9]\d{1,14}$/;
            if (!phoneRegex.test(body.to)) {
                return {
                    status: 400,
                    jsonBody: {
                        success: false,
                        error: 'Invalid phone number format. Use E.164 format (e.g., +1234567890)'
                    }
                };
            }

            // Validate message length (Twilio SMS limit)
            if (body.message.length > 1600) {
                return {
                    status: 400,
                    jsonBody: {
                        success: false,
                        error: 'Message exceeds maximum length of 1600 characters'
                    }
                };
            }

            const twilioPhoneNumber = process.env.TWILIO_PHONE_NUMBER;
            if (!twilioPhoneNumber) {
                throw new Error('TWILIO_PHONE_NUMBER environment variable is not configured.');
            }

            const client = getTwilioClient();

            const message = await client.messages.create({
                body: body.message,
                from: twilioPhoneNumber,
                to: body.to
            });

            context.log(`SMS sent successfully. SID: ${message.sid}`);

            return {
                status: 200,
                jsonBody: {
                    success: true,
                    message: 'SMS sent successfully',
                    messageSid: message.sid
                }
            };
        } catch (error) {
            context.error('Error sending SMS:', error.message);
            // Do not leak internal error details to the client
            return {
                status: 500,
                jsonBody: {
                    success: false,
                    error: 'Failed to send SMS. Please try again later.'
                }
            };
        }
    }
});

app.http('sendNotification', {
    methods: ['POST'],
    authLevel: 'function',
    route: 'notifications/both',
    handler: async (request, context) => {
        context.log('Processing combined notification request');

        try {
            const body = await request.json();

            // Input validation
            if (!body.email || !body.phone || !body.subject || !body.message) {
                return {
                    status: 400,
                    jsonBody: {
                        success: false,
                        error: 'Missing required fields: email, phone, subject, message'
                    }
                };
            }

            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            if (!emailRegex.test(body.email)) {
                return {
                    status: 400,
                    jsonBody: {
                        success: false,
                        error: 'Invalid email address format'
                    }
                };
            }

            const phoneRegex = /^\+[1-9]\d{1,14}$/;
            if (!phoneRegex.test(body.phone)) {
                return {
                    status: 400,
                    jsonBody: {
                        success: false,
                        error: 'Invalid phone number format. Use E.164 format (e.g., +1234567890)'
                    }
                };
            }

            const fromEmail = process.env.NOTIFICATION_FROM_EMAIL;
            const twilioPhoneNumber = process.env.TWILIO_PHONE_NUMBER;
            if (!fromEmail || !twilioPhoneNumber) {
                throw new Error('NOTIFICATION_FROM_EMAIL and TWILIO_PHONE_NUMBER environment variables must be configured.');
            }

            const results = {
                email: { success: false },
                sms: { success: false }
            };

            // Send email
            try {
                const sgClient = getSendGridClient();
                const msg = {
                    to: body.email,
                    from: fromEmail,
                    subject: body.subject,
                    text: body.message,
                    html: body.htmlBody || undefined
                };
                await sgClient.send(msg);
                results.email.success = true;
                context.log(`Email sent successfully to ${body.email}`);
            } catch (emailError) {
                context.error('Email sending failed:', emailError.message);
                results.email.error = 'Failed to send email';
            }

            // Send SMS
            try {
                const twilioClient = getTwilioClient();
                const smsMessage = await twilioClient.messages.create({
                    body: body.message,
                    from: twilioPhoneNumber,
                    to: body.phone
                });
                results.sms.success = true;
                results.sms.messageSid = smsMessage.sid;
                context.log(`SMS sent successfully. SID: ${smsMessage.sid}`);
            } catch (smsError) {
                context.error('SMS sending failed:', smsError.message);
                results.sms.error = 'Failed to send SMS';
            }

            const allSuccessful = results.email.success && results.sms.success;

            return {
                status: allSuccessful ? 200 : 207,
                jsonBody: {
                    success: allSuccessful,
                    message: allSuccessful
                        ? 'All notifications sent successfully'
                        : 'Some notifications failed',
                    results
                }
            };
        } catch (error) {
            context.error('Error processing notification:', error.message);
            return {
                status: 500,
                jsonBody: {
                    success: false,
                    error: 'Failed to process notification request. Please try again later.'
                }
            };
        }
    }
});